changeSet.sql:
UPDATE feedback_questions SET question_details = jsonb_set( question_details::jsonb, '{questionType}', to_jsonb(CASE WHEN COALESCE((question_details::jsonb ->> 'distributeToRecipients')::boolean, false) THEN 'CONSTSUM_RECIPIENTS' ELSE 'CONSTSUM_OPTIONS' END), false )::text WHERE question_details::jsonb ->> 'questionType' = 'CONSTSUM';
UPDATE feedback_questions SET dtype = CASE question_details::jsonb ->> 'questionType' WHEN 'CONSTSUM_OPTIONS' THEN 'FeedbackConstantSumOptionsQuestion' WHEN 'CONSTSUM_RECIPIENTS' THEN 'FeedbackConstantSumRecipientsQuestion' END WHERE question_details::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');
UPDATE feedback_questions SET question_details = (question_details::jsonb - 'distributeToRecipients')::text WHERE question_details::jsonb ->> 'questionType' = 'CONSTSUM_OPTIONS';
UPDATE feedback_questions SET question_details = ( question_details::jsonb - 'distributeToRecipients' - 'constSumOptions' - 'minPoint' - 'maxPoint' )::text WHERE question_details::jsonb ->> 'questionType' = 'CONSTSUM_RECIPIENTS';
UPDATE feedback_responses fr SET answer = jsonb_set( fr.answer::jsonb, '{questionType}', to_jsonb(fq.question_details::jsonb ->> 'questionType'), false )::text FROM feedback_questions fq WHERE fr.question_id = fq.id AND fr.answer::jsonb ->> 'questionType' = 'CONSTSUM' AND fq.question_details::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');
UPDATE feedback_responses fr SET dtype = CASE fq.question_details::jsonb ->> 'questionType' WHEN 'CONSTSUM_OPTIONS' THEN 'FeedbackConstantSumOptionsResponse' WHEN 'CONSTSUM_RECIPIENTS' THEN 'FeedbackConstantSumRecipientsResponse' END FROM feedback_questions fq WHERE fr.question_id = fq.id AND fr.answer::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS') AND fq.question_details::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');

rollback.sql:
UPDATE feedback_questions SET dtype = 'FeedbackConstantSumQuestion' WHERE question_details::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');
UPDATE feedback_responses SET dtype = 'FeedbackConstantSumResponse' WHERE answer::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');
UPDATE feedback_questions SET question_details = jsonb_set( question_details::jsonb, '{distributeToRecipients}', to_jsonb(false), true )::text WHERE question_details::jsonb ->> 'questionType' = 'CONSTSUM_OPTIONS';
UPDATE feedback_questions SET question_details = jsonb_set( jsonb_set( question_details::jsonb, '{distributeToRecipients}', to_jsonb(true), true ), '{constSumOptions}', to_jsonb(ARRAY[]::text[]), true )::text WHERE question_details::jsonb ->> 'questionType' = 'CONSTSUM_RECIPIENTS';
UPDATE feedback_questions SET question_details = jsonb_set( question_details::jsonb, '{questionType}', to_jsonb('CONSTSUM'::text), false )::text WHERE question_details::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');
UPDATE feedback_responses SET answer = jsonb_set( answer::jsonb, '{questionType}', to_jsonb('CONSTSUM'::text), false )::text WHERE answer::jsonb ->> 'questionType' IN ('CONSTSUM_OPTIONS', 'CONSTSUM_RECIPIENTS');
